package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.*;
import java.io.StringReader;
import java.time.Instant;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Service
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";

    public Document parseXml(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: Prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new InputSource(new StringReader(xml)));
    }

    public void validateResponseStatus(Document document) throws SamlProcessingException {
        NodeList statusCodeNodes = document.getElementsByTagNameNS(SAML_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() == 0) {
            throw new SamlProcessingException("No StatusCode element found in SAML response");
        }

        Element statusCode = (Element) statusCodeNodes.item(0);
        String statusValue = statusCode.getAttribute("Value");

        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusValue)) {
            // Try to get status message
            NodeList statusMessages = document.getElementsByTagNameNS(SAML_PROTOCOL_NS, "StatusMessage");
            String message = statusMessages.getLength() > 0 ? statusMessages.item(0).getTextContent() : "Unknown error";
            throw new SamlProcessingException("SAML authentication failed with status: " + statusValue + " - " + message);
        }

        logger.debug("SAML response status: Success");
    }

    public void validateResponseTimestamps(Document document, int allowedSkewSeconds) throws SamlProcessingException {
        NodeList conditions = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "Conditions");
        if (conditions.getLength() > 0) {
            Element conditionsElement = (Element) conditions.item(0);
            String notBefore = conditionsElement.getAttribute("NotBefore");
            String notOnOrAfter = conditionsElement.getAttribute("NotOnOrAfter");

            Instant now = Instant.now();

            if (notBefore != null && !notBefore.isEmpty()) {
                Instant notBeforeInstant = Instant.from(DateTimeFormatter.ISO_INSTANT.parse(notBefore));
                if (now.plusSeconds(allowedSkewSeconds).isBefore(notBeforeInstant)) {
                    throw new SamlProcessingException("SAML assertion is not yet valid. NotBefore: " + notBefore);
                }
            }

            if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                Instant notOnOrAfterInstant = Instant.from(DateTimeFormatter.ISO_INSTANT.parse(notOnOrAfter));
                if (now.minusSeconds(allowedSkewSeconds).isAfter(notOnOrAfterInstant)) {
                    throw new SamlProcessingException("SAML assertion has expired. NotOnOrAfter: " + notOnOrAfter);
                }
            }

            logger.debug("SAML response timestamps validated successfully");
        }
    }

    public void validateAudienceRestriction(Document document, String expectedAudience) throws SamlProcessingException {
        NodeList audienceNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "Audience");
        if (audienceNodes.getLength() > 0) {
            boolean audienceMatch = false;
            for (int i = 0; i < audienceNodes.getLength(); i++) {
                String audience = audienceNodes.item(i).getTextContent().trim();
                if (expectedAudience.equals(audience)) {
                    audienceMatch = true;
                    break;
                }
            }
            if (!audienceMatch) {
                throw new SamlProcessingException("SAML audience restriction check failed. Expected: " + expectedAudience);
            }
            logger.debug("Audience restriction validated for: {}", expectedAudience);
        }
    }

    public void validateDestination(Document document, String expectedDestination) throws SamlProcessingException {
        Element responseElement = document.getDocumentElement();
        String destination = responseElement.getAttribute("Destination");
        if (destination != null && !destination.isEmpty()) {
            if (!expectedDestination.equals(destination)) {
                throw new SamlProcessingException("SAML response destination mismatch. Expected: "
                        + expectedDestination + ", Got: " + destination);
            }
            logger.debug("Destination validated: {}", destination);
        }
    }

    public SamlUserAttributes extractUserAttributes(Document document) throws SamlProcessingException {
        SamlUserAttributes userAttributes = new SamlUserAttributes();

        // Extract Issuer
        NodeList issuerNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            userAttributes.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract NameID
        NodeList nameIdNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            userAttributes.setNameId(nameIdElement.getTextContent().trim());
            String format = nameIdElement.getAttribute("Format");
            if (format != null && !format.isEmpty()) {
                userAttributes.setNameIdFormat(format);
            }
        } else {
            throw new SamlProcessingException("No NameID found in SAML assertion");
        }

        // Extract SessionIndex
        NodeList authnStatements = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "AuthnStatement");
        if (authnStatements.getLength() > 0) {
            Element authnStatement = (Element) authnStatements.item(0);
            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            if (sessionIndex != null && !sessionIndex.isEmpty()) {
                userAttributes.setSessionIndex(sessionIndex);
            }
        }

        // Extract AuthnContextClassRef
        NodeList authnContextClassRefNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "AuthnContextClassRef");
        if (authnContextClassRefNodes.getLength() > 0) {
            userAttributes.setAuthnContextClassRef(authnContextClassRefNodes.item(0).getTextContent().trim());
        }

        // Extract Attributes
        Map<String, List<String>> attributes = new HashMap<>();
        NodeList attributeNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attributeElement = (Element) attributeNodes.item(i);
            String attrName = attributeElement.getAttribute("Name");
            String friendlyName = attributeElement.getAttribute("FriendlyName");

            List<String> values = new ArrayList<>();
            NodeList attributeValues = attributeElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "AttributeValue");

            for (int j = 0; j < attributeValues.getLength(); j++) {
                String value = attributeValues.item(j).getTextContent().trim();
                if (!value.isEmpty()) {
                    values.add(value);
                }
            }

            if (!values.isEmpty()) {
                attributes.put(attrName, values);
                // Also store by friendly name if available
                if (friendlyName != null && !friendlyName.isEmpty()) {
                    attributes.put(friendlyName, values);
                }
            }
        }

        userAttributes.setAttributes(attributes);

        logger.info("Extracted SAML user attributes for NameID: {}", userAttributes.getNameId());
        logger.debug("User attributes: {}", userAttributes);

        return userAttributes;
    }
}

