package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.core.io.ClassPathResource;
import org.springframework.core.io.FileSystemResource;
import org.springframework.core.io.Resource;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import java.io.InputStream;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Iterator;

@Service
public class SamlSignatureValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlSignatureValidator.class);
    private static final String XML_DSIG_NS = "http://www.w3.org/2000/09/xmldsig#";

    @Autowired
    private SamlConfig samlConfig;

    private X509Certificate idpCertificate;

    public X509Certificate getIdpCertificate() throws Exception {
        if (idpCertificate == null) {
            String certPath = samlConfig.getIdpCertificatePath();
            Resource resource;
            if (certPath.startsWith("classpath:")) {
                resource = new ClassPathResource(certPath.substring("classpath:".length()));
            } else {
                resource = new FileSystemResource(certPath);
            }

            try (InputStream is = resource.getInputStream()) {
                CertificateFactory cf = CertificateFactory.getInstance("X.509");
                idpCertificate = (X509Certificate) cf.generateCertificate(is);
            }
        }
        return idpCertificate;
    }

    public boolean validateSignature(Document document) throws Exception {
        NodeList signatureNodes = document.getElementsByTagNameNS(XML_DSIG_NS, "Signature");

        if (signatureNodes.getLength() == 0) {
            if (samlConfig.isWantAssertionsSigned()) {
                throw new SamlProcessingException("No signature found in SAML response but signatures are required");
            }
            logger.warn("No signature found in SAML response - proceeding without signature validation");
            return true;
        }

        X509Certificate cert = getIdpCertificate();
        PublicKey publicKey = cert.getPublicKey();

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            DOMValidateContext validateContext = new DOMValidateContext(
                    new SimpleKeySelector(publicKey), signatureNodes.item(i));

            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

            boolean coreValid = signature.validate(validateContext);

            if (!coreValid) {
                // Detailed validation logging
                boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                logger.error("Signature value validation: {}", signatureValueValid);

                Iterator<Reference> refIter = signature.getSignedInfo().getReferences().iterator();
                while (refIter.hasNext()) {
                    Reference ref = refIter.next();
                    boolean refValid = ref.validate(validateContext);
                    logger.error("Reference URI: {} valid: {}", ref.getURI(), refValid);
                }

                throw new SamlProcessingException("SAML response signature validation failed");
            }
        }

        logger.info("SAML response signature validated successfully");
        return true;
    }

    private static class SimpleKeySelector extends KeySelector {
        private final PublicKey publicKey;

        SimpleKeySelector(PublicKey publicKey) {
            this.publicKey = publicKey;
        }

        @Override
        public KeySelectorResult select(KeyInfo keyInfo, KeySelector.Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context) {
            return () -> publicKey;
        }
    }
}

