package com.enterprise.samlsp.service;

import com.enterprise.samlsp.config.SamlConfig;
import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.security.SamlAuthenticationToken;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;

import javax.servlet.http.HttpSession;
import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.*;
import java.util.zip.Deflater;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);

    public static final String SESSION_ATTR_SAML_USER = "SAML_USER_ATTRIBUTES";
    public static final String SESSION_ATTR_AUTH_TIME = "SAML_AUTH_TIME";
    public static final String SESSION_ATTR_NAME_ID = "SAML_NAME_ID";
    public static final String SESSION_ATTR_SESSION_INDEX = "SAML_SESSION_INDEX";

    @Autowired
    private SamlConfig samlConfig;

    @Autowired
    private SamlResponseParser responseParser;

    @Autowired
    private SamlSignatureValidator signatureValidator;

    public SamlUserAttributes processSamlResponse(String samlResponseBase64, HttpSession session)
            throws SamlProcessingException {
        try {
            // Decode Base64
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
            String samlResponseXml = new String(decodedBytes, StandardCharsets.UTF_8);

            logger.debug("Decoded SAML response XML: {}", samlResponseXml);

            // Parse XML
            Document document = responseParser.parseXml(samlResponseXml);

            // Validate response status
            responseParser.validateResponseStatus(document);

            // Validate destination
            responseParser.validateDestination(document, samlConfig.getAcsUrl());

            // Validate signature
            signatureValidator.validateSignature(document);

            // Validate timestamps
            responseParser.validateResponseTimestamps(document, samlConfig.getResponseSkew());

            // Validate audience restriction
            responseParser.validateAudienceRestriction(document, samlConfig.getEntityId());

            // Extract user attributes
            SamlUserAttributes userAttributes = responseParser.extractUserAttributes(document);

            // Validate issuer
            if (samlConfig.getIdpEntityId() != null && !samlConfig.getIdpEntityId().isEmpty()) {
                if (!samlConfig.getIdpEntityId().equals(userAttributes.getIssuer())) {
                    throw new SamlProcessingException("SAML issuer mismatch. Expected: "
                            + samlConfig.getIdpEntityId() + ", Got: " + userAttributes.getIssuer());
                }
            }

            // Store attributes in session
            storeInSession(session, userAttributes);

            // Create Spring Security authentication
            createSecurityContext(userAttributes);

            logger.info("SAML authentication successful for user: {}", userAttributes.getNameId());

            return userAttributes;

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to process SAML response: " + e.getMessage(), e);
        }
    }

    private void storeInSession(HttpSession session, SamlUserAttributes userAttributes) {
        session.setAttribute(SESSION_ATTR_SAML_USER, userAttributes);
        session.setAttribute(SESSION_ATTR_AUTH_TIME, Instant.now().toString());
        session.setAttribute(SESSION_ATTR_NAME_ID, userAttributes.getNameId());

        if (userAttributes.getSessionIndex() != null) {
            session.setAttribute(SESSION_ATTR_SESSION_INDEX, userAttributes.getSessionIndex());
        }

        // Store individual commonly-used attributes for easy access
        if (userAttributes.getEmail() != null) {
            session.setAttribute("user.email", userAttributes.getEmail());
        }
        if (userAttributes.getDisplayName() != null) {
            session.setAttribute("user.displayName", userAttributes.getDisplayName());
        }
        if (userAttributes.getFirstName() != null) {
            session.setAttribute("user.firstName", userAttributes.getFirstName());
        }
        if (userAttributes.getLastName() != null) {
            session.setAttribute("user.lastName", userAttributes.getLastName());
        }

        // Store all custom attributes with prefix
        for (Map.Entry<String, List<String>> entry : userAttributes.getAttributes().entrySet()) {
            session.setAttribute("saml.attr." + entry.getKey(), entry.getValue());
        }

        logger.debug("Stored SAML user attributes in session: {}", session.getId());
    }

    private void createSecurityContext(SamlUserAttributes userAttributes) {
        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Check for role/group attributes
        List<String> roles = userAttributes.getAttributes().get("roles");
        if (roles == null) roles = userAttributes.getAttributes().get("groups");
        if (roles == null) roles = userAttributes.getAttributes().get("http://schemas.microsoft.com/ws/2008/06/identity/claims/role");
        if (roles == null) roles = userAttributes.getAttributes().get("memberOf");

        if (roles != null) {
            for (String role : roles) {
                String normalizedRole = role.toUpperCase().startsWith("ROLE_") ? role.toUpperCase() : "ROLE_" + role.toUpperCase();
                authorities.add(new SimpleGrantedAuthority(normalizedRole));
            }
        }

        SamlAuthenticationToken authentication = new SamlAuthenticationToken(
                userAttributes.getNameId(), userAttributes, authorities);

        SecurityContextHolder.getContext().setAuthentication(authentication);

        logger.debug("Security context created for user: {} with authorities: {}",
                userAttributes.getNameId(), authorities);
    }

    public String generateAuthnRequest() throws SamlProcessingException {
        try {
            String requestId = "_" + UUID.randomUUID().toString();
            String issueInstant = Instant.now().toString();

            String authnRequest = String.format(
                    "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                            "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                            "ID=\"%s\" " +
                            "Version=\"2.0\" " +
                            "IssueInstant=\"%s\" " +
                            "Destination=\"%s\" " +
                            "AssertionConsumerServiceURL=\"%s\" " +
                            "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                            "<saml:Issuer>%s</saml:Issuer>" +
                            "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" AllowCreate=\"true\"/>" +
                            "</samlp:AuthnRequest>",
                    requestId, issueInstant, samlConfig.getIdpSsoUrl(),
                    samlConfig.getAcsUrl(), samlConfig.getEntityId()
            );

            return authnRequest;

        } catch (Exception e) {
            throw new SamlProcessingException("Failed to generate AuthnRequest: " + e.getMessage(), e);
        }
    }

    public String buildRedirectUrl() throws SamlProcessingException {
        try {
            String authnRequest = generateAuthnRequest();
            byte[] authnRequestBytes = authnRequest.getBytes(StandardCharsets.UTF_8);

            // Deflate
            Deflater deflater = new Deflater(Deflater.DEFLATED, true);
            deflater.setInput(authnRequestBytes);
            deflater.finish();

            byte[] deflatedBytes = new byte[authnRequestBytes.length * 2];
            int deflatedLength = deflater.deflate(deflatedBytes);
            deflater.end();

            byte[] trimmedBytes = new byte[deflatedLength];
            System.arraycopy(deflatedBytes, 0, trimmedBytes, 0, deflatedLength);

            // Base64 encode
            String encoded = Base64.getEncoder().encodeToString(trimmedBytes);

            // URL encode
            String urlEncoded = URLEncoder.encode(encoded, StandardCharsets.UTF_8.name());

            String redirectUrl = samlConfig.getIdpSsoUrl() + "?SAMLRequest=" + urlEncoded;

            logger.debug("Generated SAML redirect URL to IdP: {}", samlConfig.getIdpSsoUrl());

            return redirectUrl;

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to build redirect URL: " + e.getMessage(), e);
        }
    }
}

