// SamlSessionManager.java
// ============================================
package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.servlet.http.HttpSession;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SamlSessionManager {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionManager.class);

    // Maps SAML session index to HTTP session ID
    private final Map<String, String> samlSessionMap = new ConcurrentHashMap<>();
    // Maps HTTP session ID to HttpSession for SLO
    private final Map<String, HttpSession> httpSessionMap = new ConcurrentHashMap<>();

    public void registerSession(String samlSessionIndex, HttpSession httpSession) {
        if (samlSessionIndex != null) {
            samlSessionMap.put(samlSessionIndex, httpSession.getId());
            httpSessionMap.put(httpSession.getId(), httpSession);
            logger.debug("Registered SAML session: {} -> HTTP session: {}", samlSessionIndex, httpSession.getId());
        }
    }

    public void removeSession(HttpSession httpSession) {
        String sessionId = httpSession.getId();
        httpSessionMap.remove(sessionId);

        samlSessionMap.entrySet().removeIf(entry -> entry.getValue().equals(sessionId));
        logger.debug("Removed session: {}", sessionId);
    }

    public HttpSession getHttpSession(String samlSessionIndex) {
        String httpSessionId = samlSessionMap.get(samlSessionIndex);
        if (httpSessionId != null) {
            return httpSessionMap.get(httpSessionId);
        }
        return null;
    }

    public void invalidateSession(String samlSessionIndex) {
        HttpSession session = getHttpSession(samlSessionIndex);
        if (session != null) {
            try {
                session.invalidate();
                logger.info("Invalidated session for SAML session index: {}", samlSessionIndex);
            } catch (IllegalStateException e) {
                logger.debug("Session already invalidated for SAML session index: {}", samlSessionIndex);
            }
        }
    }

    public boolean isAuthenticated(HttpSession session) {
        return session.getAttribute(SamlAuthenticationService.SESSION_ATTR_SAML_USER) != null;
    }

    public SamlUserAttributes getUserAttributes(HttpSession session) {
        return (SamlUserAttributes) session.getAttribute(SamlAuthenticationService.SESSION_ATTR_SAML_USER);
    }
}

