package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.service.SamlAuthenticationService;
import com.enterprise.samlsp.service.SamlProcessingException;
import com.enterprise.samlsp.service.SamlSessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    @Autowired
    private SamlAuthenticationService authenticationService;

    @Autowired
    private SamlSessionManager sessionManager;

    @GetMapping("/saml/login")
    public void initiateLogin(HttpServletResponse response) throws IOException {
        try {
            String redirectUrl = authenticationService.buildRedirectUrl();
            logger.info("Initiating SAML login - redirecting to IdP");
            response.sendRedirect(redirectUrl);
        } catch (SamlProcessingException e) {
            logger.error("Failed to initiate SAML login", e);
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Failed to initiate SSO login");
        }
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            HttpSession session,
            Model model) {

        try {
            logger.info("Received SAML response at ACS endpoint");

            SamlUserAttributes userAttributes = authenticationService.processSamlResponse(samlResponse, session);

            // Register session for SLO support
            if (userAttributes.getSessionIndex() != null) {
                sessionManager.registerSession(userAttributes.getSessionIndex(), session);
            }

            logger.info("User '{}' authenticated successfully via SAML", userAttributes.getNameId());

            // Redirect to relay state or dashboard
            if (relayState != null && !relayState.isEmpty()) {
                return "redirect:" + relayState;
            }

            return "redirect:/dashboard";

        } catch (SamlProcessingException e) {
            logger.error("SAML authentication failed: {}", e.getMessage(), e);
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "error";
        }
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);

        if (userAttributes == null) {
            return "redirect:/saml/login";
        }

        model.addAttribute("user", userAttributes);
        model.addAttribute("nameId", userAttributes.getNameId());
        model.addAttribute("email", userAttributes.getEmail());
        model.addAttribute("displayName", userAttributes.getDisplayName());
        model.addAttribute("firstName", userAttributes.getFirstName());
        model.addAttribute("lastName", userAttributes.getLastName());
        model.addAttribute("attributes", userAttributes.getAttributes());
        model.addAttribute("authTime", session.getAttribute(SamlAuthenticationService.SESSION_ATTR_AUTH_TIME));

        return "dashboard";
    }

    @GetMapping("/saml/logout")
    public String logout(HttpSession session) {
        logger.info("User logout initiated for: {}",
                session.getAttribute(SamlAuthenticationService.SESSION_ATTR_NAME_ID));

        sessionManager.removeSession(session);
        SecurityContextHolder.clearContext();
        session.invalidate();

        return "redirect:/";
    }

    @PostMapping("/saml/slo")
    public void singleLogout(
            @RequestParam("SAMLRequest") String samlLogoutRequest,
            HttpServletResponse response) throws IOException {

        logger.info("Received SLO request from IdP");
        // Process SLO request - simplified implementation
        // In production, parse the LogoutRequest XML, extract SessionIndex, and invalidate
        response.setStatus(HttpServletResponse.SC_OK);
    }

    @GetMapping("/saml/metadata")
    @ResponseBody
    public String metadata() {
        return generateSpMetadata();
    }

    private String generateSpMetadata() {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n" +
                "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" " +
                "entityID=\"${saml.entityId}\">\n" +
                "  <md:SPSSODescriptor AuthnRequestsSigned=\"false\" " +
                "WantAssertionsSigned=\"true\" " +
                "protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">\n" +
                "    <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>\n" +
                "    <md:AssertionConsumerService " +
                "Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" " +
                "Location=\"${saml.acsUrl}\" index=\"0\" isDefault=\"true\"/>\n" +
                "  </md:SPSSODescriptor>\n" +
                "</md:EntityDescriptor>";
    }
}

// ============================================
// SecurityConfig.java
// ============================================
package com.enterprise.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf()
                .ignoringAntMatchers("/saml/acs", "/saml/slo")
            .and()
            .authorizeRequests()
                .antMatchers("/", "/saml/login", "/saml/acs", "/saml/slo", "/saml/metadata",
                        "/error", "/css/**", "/js/**", "/images/**").permitAll()
                .antMatchers("/dashboard", "/profile", "/api/**").authenticated()
                .anyRequest().authenticated()
            .and()
            .formLogin().disable()
            .httpBasic().disable()
            .logout()
                .logoutUrl("/saml/logout")
                .logoutSuccessUrl("/")
                .invalidateHttpSession(true)
                .clearAuthentication(true);

        return http.build();
    }
}

