package com.enterprise.samlsp.config;

import com.enterprise.samlsp.service.SamlSessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;

import javax.servlet.http.HttpSessionEvent;
import javax.servlet.http.HttpSessionListener;

@Component
public class SamlSessionListener implements HttpSessionListener {

    private static final Logger logger = LoggerFactory.getLogger(SamlSessionListener.class);

    @Autowired
    private SamlSessionManager sessionManager;

    @Override
    public void sessionDestroyed(HttpSessionEvent event) {
        logger.debug("HTTP session destroyed: {}", event.getSession().getId());
        sessionManager.removeSession(event.getSession());
    }
}

