// SamlApiController.java - REST API for SAML user info
// ============================================
package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.security.SamlAuthenticationToken;
import com.enterprise.samlsp.service.SamlSessionManager;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class SamlApiController {

    @Autowired
    private SamlSessionManager sessionManager;

    @GetMapping("/user/info")
    public ResponseEntity<Map<String, Object>> getUserInfo(HttpSession session) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);

        if (userAttributes == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("nameId", userAttributes.getNameId());
        userInfo.put("email", userAttributes.getEmail());
        userInfo.put("displayName", userAttributes.getDisplayName());
        userInfo.put("firstName", userAttributes.getFirstName());
        userInfo.put("lastName", userAttributes.getLastName());
        userInfo.put("issuer", userAttributes.getIssuer());
        userInfo.put("sessionIndex", userAttributes.getSessionIndex());
        userInfo.put("attributes", userAttributes.getAttributes());

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/user/attributes")
    public ResponseEntity<Map<String, List<String>>> getUserAttributes(HttpSession session) {
        SamlUserAttributes userAttributes = sessionManager.getUserAttributes(session);

        if (userAttributes == null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();
        }

        return ResponseEntity.ok(userAttributes.getAttributes());
    }

    @GetMapping("/user/authenticated")
    public ResponseEntity<Map<String, Object>> isAuthenticated(HttpSession session) {
        Map<String, Object> result = new HashMap<>();

        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        boolean authenticated = auth instanceof SamlAuthenticationToken && auth.isAuthenticated();

        result.put("authenticated", authenticated);
        if (authenticated) {
            result.put("principal", auth.getPrincipal());
            result.put("authorities", auth.getAuthorities());
        }

        return ResponseEntity.ok(result);
    }
}